module tb_trojan_1;

  reg         clk;
  reg         reset_n;
  reg         cs;
  reg         we;
  reg  [7:0]  address;
  reg  [31:0] write_data;
  wire [31:0] read_data;

  aes dut (
    .clk        (clk),
    .reset_n    (reset_n),
    .cs         (cs),
    .we         (we),
    .address    (address),
    .write_data (write_data),
    .read_data  (read_data)
  );

  always #5 clk = ~clk;

  task write_word;
    input [7:0]  addr;
    input [31:0] data;
    begin
      @(posedge clk);
      cs         = 1;
      we         = 1;
      address    = addr;
      write_data = data;
      #20;
      cs         = 0;
      we         = 0;
    end
  endtask

  task read_word;
    input  [7:0]  addr;
    output [31:0] data;
    begin
      @(posedge clk);
      cs         = 1;
      we         = 0;
      address    = addr;
      write_data = 32'h0;
      #20;
      data = read_data;
      cs   = 0;
    end
  endtask

  reg [127:0] key;
  reg [127:0] plaintext;
  reg [127:0] expected;
  reg [127:0] result;
  reg [31:0]  rdata;

  initial begin
    clk        = 0;
    reset_n    = 0;
    cs         = 0;
    we         = 0;
    address    = 8'h0;
    write_data = 32'h0;

    #50;
    reset_n = 1;
    #20;

    // ----------------------------------------------------------------
